}

export interface MessageUsage {
	input_tokens: number;
	output_tokens: number;
}

export interface AssistantMessage {
	type: 'assistant';
	message: {
		content: (TextContent | ToolUseContent)[];
		usage: MessageUsage;
	};
	ms: number;
	tokenCount?: number;
	costUSD?: number;
}

export interface UserMessage {
	type: 'user';
	message: {
		content: ToolResultContent[];
	};
	ms: number;
	tokenCount?: number;
	costUSD?: number;
}

export interface SystemMessage {
	type: 'system';
	subtype: 'init';
	agent: string;
	model: string;
