	cwd: string;
	ms: number;
	tokenCount?: number;
	costUSD?: number;
}

export interface ResultMessage {
	type: 'result';
	subtype: 'success' | 'error';
	duration_ms: number;
	duration_api_ms: number;
	num_turns: number;
	total_cost_usd: number;
	ms: number;
	tokenCount?: number;
	costUSD?: number;
}

export type TranscriptMessage = AssistantMessage | UserMessage | SystemMessage | ResultMessage;

